import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  it.todo("should return empty grid for empty input");
  it.todo("should return empty grid when single cell dies from underpopulation");
  it.todo("should return empty grid when two cells die from underpopulation");
  it.todo("should bring a dead cell to life when it has exactly 3 live neighbors");
  it.todo("should keep a live cell alive when it has exactly 2 live neighbors");
  it.todo("should keep a live cell alive when it has exactly 3 live neighbors");
  it.todo("should kill a live cell when it has more than 3 live neighbors");
  it.todo("should keep a 2x2 block stable as a still life");
  it.todo("should transform a vertical blinker to a horizontal blinker");
});
